package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Prepare ping command based on OS
	var cmd *exec.Cmd

	// Determine the appropriate ping command for the OS
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	default:
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	avgLatency, err := parseLatency(string(output), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avgLatency, nil
}

// parseLatency extracts the average latency from ping output
func parseLatency(output string, osType string) (float64, error) {
	var pattern string

	switch osType {
	case "windows":
		// Windows ping output format: "Average = XXms"
		pattern = `Average\s*=\s*(\d+(?:\.\d+)?)ms`
	default:
		// Unix-like systems (Linux, macOS) ping output format: "avg = XX.XX/XX.XX/XX.XX/XX.XX ms"
		pattern = `avg\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`
	}

	re := regexp.MustCompile(pattern)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not find average latency in ping output")
	}

	avgStr := strings.TrimSpace(matches[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
