// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Prepare ping command arguments based on OS
	var args []string
	if isWindows() {
		args = []string{"-n", fmt.Sprintf("%d", count), host}
	} else {
		args = []string{"-c", fmt.Sprintf("%d", count), host}
	}

	// Execute ping command
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	average := sum / float64(len(latencies))
	return average, nil
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Different regex patterns for different OS outputs
	// Linux/Mac: time=XX.XX ms
	// Windows: time=XXms or time<XXms
	patterns := []string{
		`time[<=]*(\d+\.?\d*)\s*ms`,
		`time[<=]*(\d+)\s*ms`,
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindAllStringSubmatch(output, -1)

		if len(matches) > 0 {
			for _, match := range matches {
				if len(match) > 1 {
					value, err := strconv.ParseFloat(match[1], 64)
					if err != nil {
						continue
					}
					latencies = append(latencies, value)
				}
			}
			if len(latencies) > 0 {
				return latencies, nil
			}
		}
	}

	// If no matches found with regex, try line-by-line parsing
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "time") {
			// Try to extract time value
			parts := strings.Fields(line)
			for i, part := range parts {
				if strings.Contains(part, "time") && i+1 < len(parts) {
					valueStr := strings.TrimSuffix(parts[i+1], "ms")
					valueStr = strings.TrimPrefix(valueStr, "=")
					valueStr = strings.TrimPrefix(valueStr, "<")
					if value, err := strconv.ParseFloat(valueStr, 64); err == nil {
						latencies = append(latencies, value)
					}
				}
			}
		}
	}

	return latencies, nil
}

