// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine ping command based on OS
	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse latencies: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	average := sum / float64(len(latencies))
	return average, nil
}

// isWindows checks if the current OS is Windows
func isWindows() bool {
	return os.Getenv("OS") == "Windows_NT" || strings.HasPrefix(os.Getenv("GOOS"), "windows")
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regex patterns for different OS formats
	// Linux/Mac format: time=X.XXX ms
	// Windows format: time=XXms or time<XXms
	patterns := []string{
		`time=([0-9.]+)\s*ms`,           // Linux/Mac format
		`time[<=]+([0-9.]+)ms`,          // Windows format
		`time=([0-9.]+)`,                // Alternative format
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindAllStringSubmatch(output, -1)

		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
				}
			}
		}

		// If we found latencies with this pattern, return them
		if len(latencies) > 0 {
			return latencies, nil
		}
	}

	return latencies, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

