// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build the ping command
	// Use -c for Linux/macOS and -n for Windows
	var cmd *exec.Cmd
	if os.PathSeparator == '\\' {
		// Windows
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		// Linux/macOS
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency information
	avgLatency, err := parseLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency: %w", err)
	}

	return avgLatency, nil
}

// parseLatency extracts the average latency from ping output
func parseLatency(output string) (float64, error) {
	var latencyPattern *regexp.Regexp
	var matches []string

	// Different patterns for Windows and Unix-like systems
	if os.PathSeparator == '\\' {
		// Windows pattern: "Average = XXms"
		latencyPattern = regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
	} else {
		// Unix pattern: "avg/min/max/stddev = X.XXX/Y.YYY/Z.ZZZ/A.AAA ms"
		latencyPattern = regexp.MustCompile(`min/avg/max/(?:stddev|mdev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	}

	matches = latencyPattern.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, fmt.Errorf("could not find average latency in ping output")
	}

	latencyStr := matches[1]
	latency, err := strconv.ParseFloat(latencyStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %w", err)
	}

	return latency, nil
}

func main() {
