package main

import (
	"errors"
	"fmt"
	"net"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 10000 {
		return 0, errors.New("count must not exceed 10000")
	}

	// Validate host is a valid hostname or IP address
	if err := validateHost(host); err != nil {
		return 0, fmt.Errorf("invalid host: %w", err)
	}

	// Use exec.Command with separate arguments to avoid shell injection
	cmd := exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// validateHost validates that the input is a valid hostname or IP address
func validateHost(host string) error {
	// Check length
	if len(host) > 253 {
		return errors.New("hostname too long")
	}

	// Try parsing as IP address
	if net.ParseIP(host) != nil {
		return nil
	}

	// Try parsing as hostname
	if _, err := net.LookupHost(host); err == nil {
		return nil
	}

	// Basic hostname format validation (alphanumeric, dots, hyphens)
	validHostname := regexp.MustCompile(`^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$`)
	if validHostname.MatchString(host) {
		return nil
	}

	return errors.New("invalid hostname or IP address format")
}

func main() {
	// Example usage
	latency, err := MeasureLatency("8.8.8.8", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

