// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine ping command based on OS
	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	average := sum / float64(len(latencies))
	return average, nil
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Pattern for Unix-like systems: "time=X.XXX ms"
	unixPattern := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := unixPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err != nil {
					continue
				}
				latencies = append(latencies, latency)
			}
		}
		return latencies, nil
	}

	// Pattern for Windows systems: "time=XXms" or "time<XXms"
	windowsPattern := regexp.MustCompile(`time[<=]+([0-9]+)ms`)
	matches = windowsPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err != nil {
					continue
				}
				latencies = append(latencies, latency)
			}
		}
		return latencies, nil
	}

	return latencies, fmt.Errorf("could not parse latency from ping output")
}

