// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Prepare ping command arguments based on OS
	var args []string
	osType := os.Getenv("GOOS")
	if osType == "windows" {
		args = []string{"-n", fmt.Sprintf("%d", count), host}
	} else {
		// Linux, macOS, and other Unix-like systems
		args = []string{"-c", fmt.Sprintf("%d", count), host}
	}

	// Execute ping command
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	outputStr := string(output)
	latencies := parseLatencies(outputStr)

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) []float64 {
	var latencies []float64

	// Pattern for Windows: "time=123ms"
	windowsPattern := regexp.MustCompile(`time=(\d+(?:\.\d+)?)ms`)
	// Pattern for Unix/Linux/macOS: "time=123.456 ms"
	unixPattern := regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s*ms`)

	// Try Windows pattern first
	matches := windowsPattern.FindAllStringSubmatch(output, -1)
	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				if val, err := strconv.ParseFloat(match[1], 64); err == nil {
					latencies = append(latencies, val)
				}
			}
		}
		return latencies
	}

	// Try Unix pattern
	matches = unixPattern.FindAllStringSubmatch(output, -1)
	for _, match := range matches {
		if len(match) > 1 {
			if val, err := strconv.ParseFloat(match[1], 64); err == nil {
				latencies = append(latencies, val)
			}
		}
	}

	return latencies
}

func main() {
