// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
// It uses the os/exec package to execute the ping command.
// Parameters:
//   - host: the target host to ping
//   - count: the number of ping attempts
// Returns:
//   - float64: the average latency in milliseconds
//   - error: an error if the ping command fails or if parsing results fails
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	// Determine the ping command based on the OS
	var cmd *exec.Cmd
	switch os := os.Getenv("GOOS"); os {
	case "windows":
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	default:
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse latencies: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// parseLatencies extracts latency values from ping command output.
// It handles both Unix-like and Windows ping output formats.
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Pattern for Unix-like systems: "time=X.XXms" or "time=X.XX ms"
	unixPattern := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := unixPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err != nil {
					continue
				}
				latencies = append(latencies, latency)
			}
		}
		return latencies, nil
	}

	// Pattern for Windows: "time<Xms" or "time=Xms"
	windowsPattern := regexp.MustCompile(`time[<=]+([0-9.]+)\s*ms`)
	matches = windowsPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err != nil {
					continue
				}
				latencies = append(latencies, latency)
			}
		}
		return latencies, nil
	}

	return latencies, fmt.Errorf("could not parse latency data from ping output")
}

func main() {
