package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 10000 {
		return 0, errors.New("count must not exceed 10000")
	}

	// Validate host to prevent command injection
	if !isValidHost(host) {
		return 0, errors.New("invalid host format")
	}

	// Use platform-specific ping command without shell injection risks
	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "min/avg/max/stddev") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt min/avg/max/mdev|min/avg/max/stddev) = \d+\.?\d*/([\d.]+)/\d+\.?\d*/\d+\.?\d*\s*(?:ms|=)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isValidHost validates the host to prevent command injection
func isValidHost(host string) bool {
	// Allow alphanumeric characters, dots, hyphens, and colons (for IPv6)
	// Reject special shell characters
	invalidChars := []string{";", "|", "&", "$", "`", "\n", "\r", "(", ")", "<", ">", "\\"}
	for _, char := range invalidChars {
		if strings.Contains(host, char) {
			return false
		}
	}

	// Basic length check
	if len(host) > 255 {
		return false
	}

	return true
}

// isWindows detects if the operating system is Windows
func isWindows() bool {
	return runtime.GOOS == "windows"
}

func main() {
	// Example usage
	latency, err := MeasureLatency("8.8.8.8", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

