// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine the ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var total float64
	for _, latency := range latencies {
		total += latency
	}
	average := total / float64(len(latencies))

	return average, nil
}

// parseLatencies extracts latency values from ping command output
func parseLatencies(output string, osType string) ([]float64, error) {
	var latencies []float64

	if osType == "windows" {
		// Windows ping output format: "Reply from ...: bytes=32 time=10ms TTL=64"
		re := regexp.MustCompile(`time[<=]+(\d+)ms`)
		matches := re.FindAllStringSubmatch(output, -1)
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
				}
			}
		}
	} else {
		// Unix/Linux/macOS ping output format: "64 bytes from ...: icmp_seq=1 ttl=64 time=10.123 ms"
		re := regexp.MustCompile(`time[<=]+(\d+\.?\d*)\s*ms`)
		matches := re.FindAllStringSubmatch(output, -1)
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
				}
			}
		}
	}

	return latencies, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
