// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Prepare the ping command
	// Use -c flag for Linux/macOS, -n flag for Windows
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract average latency
	avgLatency, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avgLatency, nil
}

// parseAverageLatency extracts the average latency from ping output
func parseAverageLatency(output string) (float64, error) {
	// Different regex patterns for different OS
	var patterns []string

	if runtime.GOOS == "windows" {
		// Windows format: "Average = 25ms"
		patterns = []string{
			`Average\s*=\s*(\d+(?:\.\d+)?)ms`,
		}
	} else {
		// Linux/macOS format: "min/avg/max/stddev = 10.123/25.456/40.789/12.345 ms"
		patterns = []string{
			`min/avg/max(?:/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`,
			`Average\s*=\s*(\d+(?:\.\d+)?)ms`,
		}
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse latency value: %w", err)
			}
			return latency, nil
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Example usage
