	}

	// Determine ping command based on OS
	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// isValidHost validates the host string to prevent command injection
func isValidHost(host string) bool {
	// Allow only alphanumeric characters, dots, hyphens, and colons (for IPv6)
	validHostPattern := regexp.MustCompile(`^[a-zA-Z0-9.\-:]+$`)
	return validHostPattern.MatchString(host)
}

// parseLatencies extracts latency values from ping command output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	lines := strings.Split(output, "\n")

	// Pattern to match latency values in different formats
	// Matches patterns like "time=10.5ms" or "time=10.5 ms"
	timePattern := regexp.MustCompile(`time[=:]?\s*(\d+\.?\d*)\s*ms`)

	for _, line := range lines {
		matches := timePattern.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	return latencies, nil
}

