	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency values found in ping output")
	}

	// Calculate average latency
	sum := 0.0
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// parseLatencies extracts latency values from ping command output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Pattern for Linux/macOS format: "time=X.XXX ms"
	unixPattern := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := unixPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
				}
			}
		}
		return latencies, nil
	}

	// Pattern for Windows format: "time<X ms" or "time=Xms"
	windowsPattern := regexp.MustCompile(`time[<=]+([0-9.]+)\s*ms`)
	matches = windowsPattern.FindAllStringSubmatch(output, -1)

	if len(matches) > 0 {
		for _, match := range matches {
			if len(match) > 1 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
				}
			}
		}
		return latencies, nil
	}

	return latencies, fmt.Errorf("unable to parse latency values from output")
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		var err error
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Printf("Invalid count value: %v\n", err)
			os.Exit(1)
		}
	}

	fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

