// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Prepare the ping command based on the operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	default:
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to ping host: %w", err)
	}

	// Parse the output to extract latency values
	latencies, err := parseLatencies(string(output), runtime.GOOS)
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// parseLatencies extracts latency values from ping command output
func parseLatencies(output string, osType string) ([]float64, error) {
	var latencies []float64

	lines := strings.Split(output, "\n")
	var pattern *regexp.Regexp
	var err error

	switch osType {
	case "windows":
		// Windows ping output format: "Reply from X.X.X.X: bytes=32 time=10ms TTL=64"
		pattern, err = regexp.Compile(`time[<=]+(\d+)ms`)
	default:
		// Unix-like ping output format: "64 bytes from X.X.X.X: icmp_seq=1 ttl=64 time=10.1 ms"
		pattern, err = regexp.Compile(`time[<=]+(\d+\.?\d*)\s*ms`)
	}

	if err != nil {
		return nil, fmt.Errorf("failed to compile regex pattern: %w", err)
	}

	for _, line := range lines {
		matches := pattern.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

