package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Validate host to prevent command injection
	// Allow valid hostnames, domain names, and IPv4/IPv6 addresses
	hostRegex := regexp.MustCompile(`^([a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?\.)*[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?$|^(\d{1,3}\.){3}\d{1,3}$|^([0-9a-fA-F]{0,4}:){2,7}[0-9a-fA-F]{0,4}$`)
	if !hostRegex.MatchString(host) {
		return 0, errors.New("invalid host format")
	}

	// Validate count is reasonable
	if count > 1000 {
		return 0, errors.New("count must not exceed 1000")
	}

	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Use platform-specific ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)
	avg, err := parseLatency(outputStr, runtime.GOOS)
	if err != nil {
		return 0, err
	}

	return avg, nil
}

// parseLatency extracts the average latency from ping output based on the OS
func parseLatency(output string, osType string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string

	// Different OS have different output formats
	searchStr := "rtt min/avg/max"
	if osType == "windows" {
		searchStr = "Minimum = "
	}

	for _, line := range lines {
		if strings.Contains(line, searchStr) {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	var re *regexp.Regexp
	if osType == "windows" {
		// Windows format: Minimum = 12ms, Maximum = 34ms, Average = 23ms
		re = regexp.MustCompile(`Average = (\d+)ms`)
	} else {
		// Unix format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		re = regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.?\d*/(\d+\.?\d*)/\d+\.?\d*/\d+\.?\d* ms`)
	}

	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	latency, err := MeasureLatency("8.8.8.8", 4)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

